CREATE TRIGGER [Authorization].[User_History]ON [Authorization].[User]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.UserId IS NOT NULL AND d.UserId IS NULL THEN 'I' 		WHEN i.UserId IS NOT NULL AND d.UserId IS NOT NULL THEN 'U' 		WHEN i.UserId IS NULL AND d.UserId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.UserId = d.UserId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Authorization_User([UserId], [LoginName], [FirstName], [LastName], [EmailAddress], [JobTitle], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UserId], [LoginName], [FirstName], [LastName], [EmailAddress], [JobTitle], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Authorization_User([UserId], [LoginName], [FirstName], [LastName], [EmailAddress], [JobTitle], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UserId], [LoginName], [FirstName], [LastName], [EmailAddress], [JobTitle], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND